function solve(n: number, edges: number[][]): number {
    // Build the graph: original edges and reversed edges (for possible flipping)
    const graph: [number, number][][] = Array.from({ length: n }, () => []);
    const reversedEdges: [number, number][][] = Array.from({ length: n }, () => []);

    for (const [u, v, w] of edges) {
        graph[u].push([v, w]);
        reversedEdges[v].push([u, w]);  // store for possible flip
    }

    // Dijkstra's setup: [total_cost, current_node, has_used_flip]
    const heap: [number, number, boolean][] = [];
    // dist[node][used_flip] = min_cost
    const dist: number[][] = Array.from({ length: n }, () => [Infinity, Infinity]);
    dist[0][0] = 0;
    heap.push([0, 0, false]);
    heap.sort((a, b) => a[0] - b[0]);

    while (heap.length > 0) {
        const [currentCost, u, usedFlip] = heap.shift()!;
        if (u === n - 1) {
            return currentCost;
        }

        if (currentCost > dist[u][usedFlip ? 1 : 0]) {
            continue;
        }

        // Explore original edges
        for (const [v, w] of graph[u]) {
            const newCost = currentCost + w;
            if (newCost < dist[v][usedFlip ? 1 : 0]) {
                dist[v][usedFlip ? 1 : 0] = newCost;
                heap.push([newCost, v, usedFlip]);
                heap.sort((a, b) => a[0] - b[0]);
            }
        }

        // If not used flip yet, try flipping an incoming edge
        if (!usedFlip) {
            for (const [v, w] of reversedEdges[u]) {
                // Flip v->u to u->v, cost is 2*w
                const newCost = currentCost + 2 * w;
                if (newCost < dist[v][1]) {
                    dist[v][1] = newCost;
                    heap.push([newCost, v, true]);
                    heap.sort((a, b) => a[0] - b[0]);
                }
            }
        }
    }

    const res = Math.min(dist[n - 1][0], dist[n - 1][1]);
    return res !== Infinity ? res : -1;
}
